typealias Edge = (dest: Int64, weight: Int64)

class MinHeap {
    private var heap: [(Int64, Int64)] = []

    var isEmpty: Bool {
        return heap.isEmpty
    }

    func push(_ value: (Int64, Int64)) {
        heap.append(value)
        siftUp(from: heap.count - 1)
    }

    func pop() -> (Int64, Int64)? {
        guard !heap.isEmpty else { return nil }
        heap.swapAt(0, heap.count - 1)
        let min = heap.removeLast()
        siftDown(from: 0)
        return min
    }

    private func siftUp(from index: Int) {
        var child = index
        var parent = (child - 1) / 2
        while child > 0 && heap[child].0 < heap[parent].0 {
            heap.swapAt(child, parent)
            child = parent
            parent = (child - 1) / 2
        }
    }

    private func siftDown(from index: Int) {
        var parent = index
        let length = heap.count
        while true {
            let left = 2 * parent + 1
            let right = 2 * parent + 2
            var candidate = parent
            if left < length && heap[left].0 < heap[candidate].0 {
                candidate = left
            }
            if right < length && heap[right].0 < heap[candidate].0 {
                candidate = right
            }
            if candidate == parent { return }
            heap.swapAt(parent, candidate)
            parent = candidate
        }
    }
}

func solve(n: Int64, edges: Array<Array<Int64>>) -> Int64 {
    if n == 1 { return 0 }

    let nInt = Int(n)
    var outEdges: [[Edge]] = Array(repeating: [], count: nInt)
    var revEdges: [[Edge]] = Array(repeating: [], count: nInt)

    for edge in edges {
        let u = edge[0]
        let v = edge[1]
        let w = edge[2]
        let ui = Int(u)
        let vi = Int(v)
        outEdges[ui].append((dest: v, weight: w))
        revEdges[vi].append((dest: u, weight: w))
    }

    var dist = Array(repeating: Int64.max, count: nInt)
    dist[0] = 0

    let pq = MinHeap()
    pq.push((0, 0))

    while let (cost, node) = pq.pop() {
        let u = Int(node)
        if cost != dist[u] { continue }

        if u == nInt - 1 {
            return cost
        }

        for edge in outEdges[u] {
            let v = Int(edge.dest)
            let w = edge.weight
            let newCost = cost + w
            if newCost < dist[v] {
                dist[v] = newCost
                pq.push((newCost, edge.dest))
            }
        }

        for edge in revEdges[u] {
            let x = Int(edge.dest)
            let w = edge.weight
            let newCost = cost + 2 * w
            if newCost < dist[x] {
                dist[x] = newCost
                pq.push((newCost, edge.dest))
            }
        }
    }

    return -1
}
```

### Explanation
1. **Graph Representation**: 
   - `outEdges` stores outgoing edges for normal traversal.
   - `revEdges` stores incoming edges which can be reversed for traversal when a node's switch is used.

2. **Dijkstra's Algorithm**:
   - **Initialization**: Start with node 0 at cost 0 in the priority queue.
   - **Processing**: For each node, process its outgoing edges (normal traversal) and incoming edges (reversed traversal, costing twice the weight).
   - **Priority Queue**: Ensures nodes are processed in order of increasing cost. Each node's cost is updated if a cheaper path is found.

3. **Termination**:
   - If node n-1 is reached, return the current cost.
   - If the queue is exhausted without reaching node n-1, return -1.

This approach efficiently explores all possible paths, including paths using reversed edges, while leveraging Dijkstra's algorithm to ensure the shortest path is found in terms of cost. The complexity is O((E + V) log V) due to the priority queue operations.

To solve this problem, we need to find the minimum cost to travel from node `0` to node `n-1` in a directed graph where each node has a switch that can be used at most once. Using the switch at a node `u` allows flipping one incoming edge to an outgoing edge, which can then be traversed immediately at twice the original cost.

### Approach
1. **Graph Representation**: We model the problem using an auxiliary graph with two layers for each node:
   - **Layer 0 (u0)**: Represents being at node `u` without having used its switch.
   - **Layer 1 (u1)**: Represents being at node `u` after having used its switch (thus, no more flips are possible at `u`).

2. **Edge Construction**:
   - **Original Edges**: For each original edge `(u, v, w)`, we add edges from `u0` to `v0` and from `u1` to `v0`, both with cost `w`. This is because moving via an original edge does not affect the switch status of the destination node.
   - **Flipped Edges**: For each original edge `(u, v, w)`, we add an edge from `v0` to `u0` with cost `2*w`. This edge represents flipping the original incoming edge at `v` to move back to `u`. Note that this edge is only available from `v0` (where the switch hasn't been used) and moves to `u0` (since flipping the edge does not affect `u`'s switch status).

3. **Dijkstra's Algorithm**: We use Dijkstra's algorithm to find the shortest path from `00` (starting at node `0` without having used its switch) to either `(n-1)0` or `(n-1)1`. The algorithm processes nodes in priority order based on accumulated cost, exploring both original and flipped edges appropriately.

### Solution Code
```cangjie
import std.cj_io;
import std.containers;
import std.cj_int64;

func solve(n: Int64, edges: Array<Array<Int64>>): Int64 {
    // Create graph: 2 * n nodes
    let numNodes: Int64 = n * 2;
    let graph = Array(mut Array(mut (Int64, Int64))(), size: numNodes, init: []);

    // Helper to get node index in the graph
    // node u in layer0: index = u
    // node u in layer1: index = u + n
    func nodeIdx(u: Int64, layer: Int64): Int64 {
        if layer == 0 { 
            return u; 
        }
        return u + n;
    }

    // Add edges to the graph
    for edge in edges {
        let u = edge[0];
        let v = edge[1];
        let w = edge[2];

        // Original edge: from layer0 and layer1 of u to layer0 of v
        let u0 = nodeIdx(u, 0);
        let u1 = nodeIdx(u, 1);
        let v0 = nodeIdx(v, 0);

        // Original edge from u0 to v0
        push(graph[u0], (v0, w));
        // Original edge from u1 to v0
        push(graph[u1], (v0, w));

        // Flip edge: from layer0 of v to layer0 of u
        let v0_flip = nodeIdx(v, 0);
        let u0_flip = nodeIdx(u, 0);
        push(graph[v0_flip], (u0_flip, w * 2));
    }

    // Dijkstra's algorithm
    let INF: Int64 = 1000000000000000; // Sufficiently large value
    let dist = Array(mut INF, size: numNodes);

    // Start from node0 at layer0: index = 0
    dist[0] = 0;

    // Priority queue: (distance, node)
    let queue = MinHeap<Pair<Int64, Int64>>(compareFunc: fn (p1: Pair<Int64, Int64>, p2: Pair<Int64, Int64>): Int64 {
        return p1.first - p2.first;
    });
    push(queue, Pair(first: 0, second: 0));

    while !empty(queue) {
        let top = pop_min(queue);
        let d = top.first;
        let u = top.second;

        if d > dist[u] {
            continue;
        }

        for neighborTuple in graph[u] {
            let v = neighborTuple[0];
            let cost = neighborTuple[1];
            let newDist: Int64 = d + cost;
            if newDist < dist[v] {
                dist[v] = newDist;
                push(queue, Pair(first: newDist, second: v));
            }
        }
    }

    let target0 = n - 1; // layer0
    let target1 = (n - 1) + n; // layer1

    let ans0 = dist[target0];
    let ans1 = dist[target1];
    let ans = min(ans0, ans1);

    if ans == INF {
        return -1;
    }
    return ans;
}
```

### Explanation
1. **Graph Construction**: The graph is built with `2 * n` nodes to represent two states per node (switch not used and switch used). Original edges are added to both states, while flipped edges (available only when the switch hasn't been used) are added from the first state of the destination node back to the source node.
2. **Dijkstra's Algorithm**: The algorithm starts from node `0` (switch not used) and processes nodes in order of increasing cost. It explores both original edges (moving to the next node without using its switch) and flipped edges (using the switch to move back to a predecessor node at twice the cost).
3. **Result Extraction**: The minimum cost to reach node `n-1` is derived by considering both states (switch used or not). If neither state is reachable, the function returns `-1`.

This approach efficiently models the problem constraints using a multi-layered graph and leverages Dijkstra's algorithm to find the minimal path cost in logarithmic time relative to the number of edges.
